#!/bin/bash\nset -e\n\nPROJECT_DIR="/opt/gameworld"\nDOMAIN="sharex.my"\n\necho "=================================="\necho "ж≠•й™§ 4: йЕНзљЃ Nginx + HTTPS"\necho "=================================="\n\n# еЃЙи£Е Certbot\necho "[1/4] еЃЙи£Е Certbot..."\napt install -y certbot python3-certbot-nginx\n\n# еИЫеїЇ Nginx йЕНзљЃ\necho "[2/4] йЕНзљЃ Nginx..."\ncat > /etc/nginx/sites-available/gameworld << 'EOF'\nserver {\n    listen 80;\n    listen [::]:80;\n    server_name sharex.my www.sharex.my;\n\n    # еЙНзЂѓйЭЩжАБжЦЗдї?
    location / {\n        root /opt/gameworld/frontend;\n        index index.html;\n        try_files $uri $uri/ /index.html;\n    }\n\n    # еРОзЂѓ API дї£зРЖ\n    location /api/ {\n        proxy_pass http://localhost:3000/;\n        proxy_http_version 1.1;\n        proxy_set_header Upgrade $http_upgrade;\n        proxy_set_header Connection 'upgrade';\n        proxy_set_header Host $host;\n        proxy_set_header X-Real-IP $remote_addr;\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n        proxy_set_header X-Forwarded-Proto $scheme;\n        proxy_cache_bypass $http_upgrade;\n    }\n\n    # Socket.io WebSocket жФѓжМБ\n    location /socket.io/ {\n        proxy_pass http://localhost:3000/socket.io/;\n        proxy_http_version 1.1;\n        proxy_set_header Upgrade $http_upgrade;\n        proxy_set_header Connection "upgrade";\n        proxy_set_header Host $host;\n        proxy_set_header X-Real-IP $remote_addr;\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n        proxy_set_header X-Forwarded-Proto $scheme;\n    }\n\n    # дЄКдЉ†жЦЗдїґиЃњйЧЃ\n    location /uploads/ {\n        alias /opt/gameworld/uploads/;\n        try_files $uri =404;\n    }\n\n    # жЧ•ењЧ\n    access_log /var/log/nginx/gameworld.access.log;\n    error_log /var/log/nginx/gameworld.error.log;\n}\nEOF\n\n# еРѓзФ®зЂЩзВє\nln -sf /etc/nginx/sites-available/gameworld /etc/nginx/sites-enabled/\nrm -f /etc/nginx/sites-enabled/default\n\n# жµЛиѓХйЕНзљЃ\nnginx -t\n\n# йЗНиљљ Nginx\nsystemctl restart nginx\nsystemctl enable nginx\n\n# йЕНзљЃ SSL\necho "[3/4] зФ≥иѓЈ SSL иѓБдє¶..."\ncertbot --nginx -d sharex.my -d www.sharex.my --agree-tos --no-eff-email --redirect --non-interactive\n\necho "[4/4] йЕНзљЃиЗ™еК®зї≠жЬЯ..."\n# жµЛиѓХиЗ™еК®зї≠жЬЯ\n# certbot renew --dry-run\n\necho ""\necho "вЬ?Nginx + HTTPS йЕНзљЃеЃМжИРпЉ?\necho ""\necho "иЃњйЧЃеЬ∞еЭА:"\necho "  https://sharex.my"\necho "  https://www.sharex.my"\necho ""\n